import '../styles/global.css';
import cjkFontsHref from '../styles/cjk-fonts.css?url';
import Header from '../components/Header.astro';
import Footer from '../components/Footer.astro';
import SEO from '../components/SEO.astro';
import { VisualEditing } from '@sanity/astro/visual-editing';
import { getAlternateUrl, type Lang } from '../lib/navigation';

interface Props {
  title: string;
  description?: string;
  lang?: string;
  jsonLd?: Record<string, unknown>;
  ogImage?: string;
  ogType?: string;
}

const {
  title,
  description = 'A Chinese-heritage, university-adjacent Christian community in Ithaca, NY.',
  lang = 'en',
  jsonLd,
  ogImage,
  ogType,
} = Astro.props;

const gaMeasurementId = import.meta.env.PUBLIC_GA_MEASUREMENT_ID;
const googleSiteVerification = import.meta.env.PUBLIC_GOOGLE_SITE_VERIFICATION;

const alternateUrl = getAlternateUrl(Astro.url.pathname, lang as Lang);
const absoluteAlternateUrl = new URL(alternateUrl, Astro.site ?? 'https://ficcc.org').href;

const isVisualEditingEnabled =
  import.meta.env.PUBLIC_SANITY_VISUAL_EDITING_ENABLED === 'true';
---

<!doctype html>
<html lang={lang}>
  <head>
    <meta charset="utf-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1" />
    <SEO title={title} description={description} lang={lang} alternateUrl={absoluteAlternateUrl} jsonLd={jsonLd} ogImage={ogImage} ogType={ogType} />
    {googleSiteVerification && <meta name="google-site-verification" content={googleSiteVerification} />}
    <link rel="preconnect" href="https://cdn.sanity.io" crossorigin />
    <link rel="stylesheet" href={cjkFontsHref} media="print" onload="this.media='all'" />
    <noscript><link rel="stylesheet" href={cjkFontsHref} /></noscript>
  </head>
  <body>
    <a href="#main-content" class="skip-to-content">Skip to main content</a>
    <Header lang={lang} langToggleHref={alternateUrl} />
    <slot />
    <Footer lang={lang} />
    {isVisualEditingEnabled && <VisualEditing enabled={true} />}
    {gaMeasurementId && (
      <>
        <script async src={`https://www.googletagmanager.com/gtag/js?id=${gaMeasurementId}`}></script>
        <script define:vars={{ gaMeasurementId }}>
          window.dataLayer = window.dataLayer || [];
          function gtag() { dataLayer.push(arguments); }
          gtag('js', new Date());
          gtag('config', gaMeasurementId);

          // Custom event helper for sermon_play, language_switch, form_submit
          window.sendAnalyticsEvent = function(eventName, params) {
            if (typeof gtag === 'function') {
              gtag('event', eventName, params || {});
            }
          };
        </script>
      </>
    )}
    <script>
      document.addEventListener('click', (e) => {
        const toggle = (e.target as HTMLElement).closest('.lang-toggle') as HTMLAnchorElement | null;
        if (toggle) {
          const targetLang = toggle.href.includes('/zh') ? 'zh' : 'en';
          document.cookie = 'lang-pref=' + targetLang + ';path=/;max-age=31536000;SameSite=Lax';
        }
      });
    </script>
  </body>
</html>

<style is:global>
  .skip-to-content {
    position: absolute;
    left: -9999px;
    top: auto;
    width: 1px;
    height: 1px;
    overflow: hidden;
    z-index: 9999;
    padding: var(--space-3) var(--space-6);
    background: var(--color-ink);
    color: var(--color-bg);
    font-family: var(--font-body);
    font-size: var(--text-base);
    text-decoration: none;
    border-radius: var(--radius-sm, 0.25rem);
  }

  .skip-to-content:focus-visible {
    position: fixed;
    left: var(--space-4);
    top: var(--space-4);
    width: auto;
    height: auto;
    overflow: visible;
    outline: 2px solid var(--color-focus);
    outline-offset: 2px;
  }
</style>

### Search Component Props

Source: https://context7.com/shishkin/astro-pagefind/llms.txt

The Search component accepts several optional props to control its behavior, styling, and initial state.

```APIDOC
## Search Component Props

### Description
The Search component is the primary interface for adding full-text search to an Astro site. It supports configuration through optional props.

### Parameters
- **id** (string) - Optional - Unique identifier for the search instance.
- **className** (string) - Optional - CSS class for custom styling.
- **query** (string) - Optional - Pre-filled search query string.
- **uiOptions** (Object) - Optional - Configuration object for the underlying Pagefind UI.

### Request Example
<Search id="main-search" className="search-box" query="getting started" />
```

--------------------------------

### Add Search Component to Astro Page

Source: https://github.com/shishkin/astro-pagefind/blob/main/README.md

Includes the Search component from astro-pagefind into an Astro page. This component renders the search interface on your website. It accepts an 'id', 'className', and 'uiOptions' for customization.

```astro
--- 
import Search from "astro-pagefind/components/Search";
--- 

<Search id="search" className="pagefind-ui" uiOptions={{ showImages: false }} />
```

--------------------------------

### Configure Pagefind Indexing Options

Source: https://context7.com/shishkin/astro-pagefind/llms.txt

Pass custom configuration options to the Pagefind service via the indexConfig property in your Astro configuration.

```typescript
import { defineConfig } from "astro/config";
import pagefind from "astro-pagefind";

export default defineConfig({
  integrations: [
    pagefind({
      indexConfig: {
        keepIndexUrl: true,
      },
    }),
  ],
});
```

--------------------------------

### Customize Pagefind UI with CSS Variables

Source: https://context7.com/shishkin/astro-pagefind/llms.txt

Shows how to apply custom styles to the Pagefind UI component using CSS variables scoped to a specific className.

```astro
---
import Search from "astro-pagefind/components/Search";
---

<Search id="search" className="pagefind-ui custom-search" />

<style is:global>
  .pagefind-ui.custom-search {
    --pagefind-ui-scale: 0.75;
    --pagefind-ui-primary: navy;
    --pagefind-ui-text: black;
    --pagefind-ui-background: lightyellow;
    --pagefind-ui-border: slategrey;
    --pagefind-ui-border-width: 1px;
    --pagefind-ui-border-radius: 0.25rem;
    --pagefind-ui-font: sans-serif;
    width: 50%;
  }

  .pagefind-ui.custom-search .pagefind-ui__drawer:not(.pagefind-ui__hidden) {
    position: absolute;
    left: 0;
    right: 0;
    z-index: 9999;
    padding: 0 2em 1em;
    overflow-y: auto;
    box-shadow: 0 10px 10px -5px rgba(0, 0, 0, 0.2);
    border-bottom-right-radius: var(--pagefind-ui-border-radius);
    border-bottom-left-radius: var(--pagefind-ui-border-radius);
    background-color: var(--pagefind-ui-background);
  }

  .pagefind-ui.custom-search .pagefind-ui__result-link {
    color: var(--pagefind-ui-primary);
  }

  .pagefind-ui.custom-search .pagefind-ui__result-excerpt {
    color: var(--pagefind-ui-text);
  }
</style>
```

--------------------------------

### Customize Search UI Options

Source: https://context7.com/shishkin/astro-pagefind/llms.txt

Use the uiOptions prop to pass configuration objects that modify the appearance and behavior of the search interface.

```astro
<Search
  id="search"
  className="pagefind-ui"
  uiOptions={{
    showImages: false,
    showEmptyFilters: true,
    excerptLength: 15,
    resetStyles: false,
    debounceTimeoutMs: 300
  }}
/>
```

